64	        vint32m8_t vZeroAccumulator1 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
65	        vint32m8_t vZeroAccumulator2 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
66	
67	        vint32m1_t vAccumulator1 = __riscv_vget_i32m1(vZeroAccumulator1, 0);
68	        vint32m1_t vAccumulator2 = __riscv_vget_i32m1(vZeroAccumulator1, 1);
69	        vint32m1_t vAccumulator3 = __riscv_vget_i32m1(vZeroAccumulator1, 2);
70	        vint32m1_t vAccumulator4 = __riscv_vget_i32m1(vZeroAccumulator1, 3);
71	        vint32m1_t vAccumulator5 = __riscv_vget_i32m1(vZeroAccumulator1, 4);
72	        vint32m1_t vAccumulator6 = __riscv_vget_i32m1(vZeroAccumulator1, 5);
73	        vint32m1_t vAccumulator7 = __riscv_vget_i32m1(vZeroAccumulator1, 6);
74	        vint32m1_t vAccumulator8 = __riscv_vget_i32m1(vZeroAccumulator1, 7);
75	
76	        vint32m1_t vAccumulator9 = __riscv_vget_i32m1(vZeroAccumulator2, 0);
77	        vint32m1_t vAccumulator10 = __riscv_vget_i32m1(vZeroAccumulator2, 1);
78	        vint32m1_t vAccumulator11 = __riscv_vget_i32m1(vZeroAccumulator2, 2);
79	        vint32m1_t vAccumulator12 = __riscv_vget_i32m1(vZeroAccumulator2, 3);
80	        vint32m1_t vAccumulator13 = __riscv_vget_i32m1(vZeroAccumulator2, 4);
81	        vint32m1_t vAccumulator14 = __riscv_vget_i32m1(vZeroAccumulator2, 5);
82	        vint32m1_t vAccumulator15 = __riscv_vget_i32m1(vZeroAccumulator2, 6);
83	        vint32m1_t vAccumulator16 = __riscv_vget_i32m1(vZeroAccumulator2, 7);
84	
85	        unsigned long colCnt = col_src1;
86	        while(colCnt > 0)
87	        {
88	            vl = __riscv_vsetvl_e8m1(colCnt);
89	            //load src1 and src2
90	            vint8m1_t vpA_i8m1 = __riscv_vle8_v_i8m1(pA, vl);
91	            vint8m1_t vpA2_i8m1 = __riscv_vle8_v_i8m1(pA2, vl);
92	            vint8m1_t vpA3_i8m1 = __riscv_vle8_v_i8m1(pA3, vl);
93	            vint8m1_t vpA4_i8m1 = __riscv_vle8_v_i8m1(pA4, vl);
94	
95	            vint8m1_t vpB_i8m1 = __riscv_vle8_v_i8m1(pB, vl);
96	            vint8m1_t vpB2_i8m1 = __riscv_vle8_v_i8m1(pB2, vl);
97	            vint8m1_t vpB3_i8m1 = __riscv_vle8_v_i8m1(pB3, vl);
98	            vint8m1_t vpB4_i8m1 = __riscv_vle8_v_i8m1(pB4, vl);
99	
100

460	        NDS_VEC_VREDSUM_VS(NDS_VEC_V5, NDS_VEC_V13, NDS_VEC_V31);
461	        NDS_VEC_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V14, NDS_VEC_V31);
462	        NDS_VEC_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V15, NDS_VEC_V31);
463	
464	        NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V31);
465	        NDS_VEC_VREDSUM_VS(NDS_VEC_V9, NDS_VEC_V17, NDS_VEC_V31);
466	        NDS_VEC_VREDSUM_VS(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V31);
467	        NDS_VEC_VREDSUM_VS(NDS_VEC_V11, NDS_VEC_V19, NDS_VEC_V31);
468	
469	        NDS_VEC_VREDSUM_VS(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V31);
470	        NDS_VEC_VREDSUM_VS(NDS_VEC_V13, NDS_VEC_V21, NDS_VEC_V31);
471	        NDS_VEC_VREDSUM_VS(NDS_VEC_V14, NDS_VEC_V22, NDS_VEC_V31);
