474	        NDS_VEC_VSETVLI_E32(vl, 4);     //4: 4 acc
475	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 1);
476	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 2);
