478	
479	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V5, 1);
480	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V6, 2);
481	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V7, 3);
482	
483	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V8, NDS_VEC_V9, 1);
484	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V8, NDS_VEC_V10, 2);
485	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V8, NDS_VEC_V11, 3);
486	
487	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V12, NDS_VEC_V13, 1);
488	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V12, NDS_VEC_V14, 2);
489	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V12, NDS_VEC_V15, 3);
490	
491	        //load bias
492	        NDS_VEC_VLW_V(NDS_VEC_V30, bias);
493	        bias += vl;
494	
495	        //add bias to acc
496	        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V30);
497	        NDS_VEC_VADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V30);
498	        NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V30);
499	        NDS_VEC_VADD_VV(NDS_VEC_V12, NDS_VEC_V12, NDS_VEC_V30);
500	
501	        // hoist NN_ROUND splat above VSRA so it overlaps with vsra latency
502	        NDS_VEC_VMV_V_X(NDS_VEC_V30, NN_ROUND(post_rshift));
503	
504	        //1st shift of 2-stage shift, interleaved with VMADD (V30 = NN_ROUND from above)
505	        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
506	        NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
507	        NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
508	        NDS_VEC_VMADD_VX(NDS_VEC_V0, out_scale, NDS_VEC_V30);
509	        NDS_VEC_VSRA_VX(NDS_VEC_V12, NDS_VEC_V12, pre_rshift);
510	        NDS_VEC_VMADD_VX(NDS_VEC_V4, out_scale, NDS_VEC_V30);
511	        NDS_VEC_VMADD_VX(NDS_VEC_V8, out_scale, NDS_VEC_V30);
512	        NDS_VEC_VMADD_VX(NDS_VEC_V12, out_scale, NDS_VEC_V30);
513	
514	        //saturate into 8-bits
515	        NDS_VEC_VSETVLI_E16(vl, 4);     //4: 4 acc
516	        NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
517	        NDS_VEC_VNSRA_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
518	        NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
519	        NDS_VEC_VNSRA_WX(NDS_VEC_V12, NDS_VEC_V12, post_rshift);
520	        NDS_VEC_VSETVLI_E8(vl, 4);     //4: 4 acc
521	        NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
522	        NDS_VEC_VNCLIP_WI(NDS_VEC_V4, NDS_VEC_V4, 0);
523	        NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
524	        NDS_VEC_VNCLIP_WI(NDS_VEC_V12, NDS_VEC_V12, 0);
525	
526	        //store the results
527	        NDS_VEC_VSB_V(NDS_VEC_V0, out);
528	        NDS_VEC_VSB_V(NDS_VEC_V4, pOut2);
529	        NDS_VEC_VSB_V(NDS_VEC_V8, pOut3);
530	        NDS_VEC_VSB_V(NDS_VEC_V12, pOut4);
531	        out += vl;
532	        pOut2 += vl;
533	        pOut3 += vl;
534	        pOut4 += vl;
535	
536	        rowCnt--;
537	    }
538	
539	    //reset rows (as out_tensor_ch is 4n+2)
540	    if(out_tensor_ch & 0x2)
541	    {
542	        // setup pointers for A
543	        const q7_t *pA2 = pA + col_src1;
544	        // setup pointers for B
545	        const q7_t *pB = src2;
546	        const q7_t *pB2 = pB + col_src1;
